import { Button } from "@/components/ui/button";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Check, ChevronDown, ChevronUp } from "lucide-react";
import * as React from "react";
import { cn } from "@/lib/utils";

const SelectContext = React.createContext<{
  value?: string;
  onChange?: (value: string) => void;
  name?: string;
  onOpenChange?: (open: boolean) => void;
  isOpen?: boolean;
  focusedIndex?: number;
  setFocusedIndex?: (index: number) => void;
  handleTypeahead?: (key: string) => void;
  registerOption?: (value: string, label: string) => void;
  unregisterOption?: (value: string) => void;
  getOptions?: () => Array<{ label: string; value: string }>;
  id?: string;
  suppressInitialScroll?: boolean;
} | null>(null);

const Select = ({
  value,
  onValueChange,
  defaultValue,
  children,
  name,
  id,
  suppressInitialScroll,
  ...rest
}: {
  value?: string;
  onValueChange?: (value: string) => void;
  defaultValue?: string;
  children: React.ReactNode;
  name?: string;
  id?: string;
  suppressInitialScroll?: boolean;
} & React.HTMLAttributes<HTMLDivElement>) => {
  const [isOpen, setIsOpen] = React.useState(false);
  const [internalValue, setInternalValue] = React.useState(defaultValue);
  const [focusedIndex, setFocusedIndex] = React.useState(-1);
  const [typeahead, setTypeahead] = React.useState("");
  const openedOnceRef = React.useRef(false);

  const optionsRef = React.useRef<Array<{ label: string; value: string }>>([]);
  const typeaheadTimeoutRef = React.useRef<number>();
  const currentValue = value ?? internalValue;

  const registerOption = React.useCallback((value: string, label: string) => {
    const existing = optionsRef.current.find((opt) => opt.value === value);
    if (existing) {
      optionsRef.current = optionsRef.current.map((opt) => (opt.value === value ? { value, label } : opt));
    } else {
      optionsRef.current = [...optionsRef.current, { value, label }];
    }
  }, []);

  const unregisterOption = React.useCallback((value: string) => {
    optionsRef.current = optionsRef.current.filter((opt) => opt.value !== value);
  }, []);

  const getOptions = React.useCallback(() => optionsRef.current, []);

  React.useEffect(() => {
    if (isOpen) {
      if (!openedOnceRef.current && suppressInitialScroll) {
        // Skip focusing any item so list remains scrolled to top (search field visible).
        setFocusedIndex(-1);
      } else if (optionsRef.current.length > 0) {
        const selectedIndex = optionsRef.current.findIndex((option) => option.value === currentValue);
        setFocusedIndex(selectedIndex >= 0 ? selectedIndex : 0);
      }
      openedOnceRef.current = true;
    } else {
      setFocusedIndex(-1);
    }
  }, [isOpen, currentValue, suppressInitialScroll]);

  const handleTypeahead = React.useCallback(
    (key: string) => {
      const options = optionsRef.current;
      if (!options || options.length === 0) return;

      if (typeaheadTimeoutRef.current) {
        clearTimeout(typeaheadTimeoutRef.current);
      }

      const newTypeahead = typeahead + key.toLowerCase();
      setTypeahead(newTypeahead);

      const matchingIndex = options.findIndex((option) => option.label.toLowerCase().startsWith(newTypeahead));

      if (matchingIndex !== -1) {
        if (isOpen) {
          setFocusedIndex(matchingIndex);
        } else {
          setIsOpen(true);
          setFocusedIndex(matchingIndex);
        }
      }

      typeaheadTimeoutRef.current = setTimeout(() => {
        setTypeahead("");
      }, 500);
    },
    [typeahead, isOpen]
  );

  return (
    <SelectContext.Provider
      value={{
        value: currentValue,
        onChange: (val) => {
          setInternalValue(val);
          onValueChange?.(val);
          setIsOpen(false);
          setFocusedIndex(-1);
        },
        name,
        onOpenChange: setIsOpen,
        isOpen,
        focusedIndex,
        setFocusedIndex,
        handleTypeahead,
        registerOption,
        unregisterOption,
        getOptions,
  id,
  suppressInitialScroll,
      }}
    >
      <Popover open={isOpen} onOpenChange={setIsOpen}>
        <div className="uci-relative uci-w-full" data-slot="select" {...rest}>
          {children}
        </div>
      </Popover>
    </SelectContext.Provider>
  );
};

const SelectGroup = ({ className, ...props }: React.HTMLAttributes<HTMLDivElement>) => {
  return <div data-slot="select-group" className={className} {...props} />;
};

const SelectValue = ({
  placeholder,
  className,
  ...props
}: {
  placeholder?: string;
  className?: string;
} & React.HTMLAttributes<HTMLSpanElement>) => {
  const context = React.useContext(SelectContext);
  if (!context) throw new Error("SelectValue must be used within Select");

  const selectedValue = context.value;
  const options = context.getOptions?.() || [];
  const selectedLabel = selectedValue && options.find((opt) => opt.value === selectedValue)?.label;

  return (
    <span data-slot="select-value" className={className} {...props}>
      {selectedLabel || placeholder}
    </span>
  );
};

const SelectTrigger = ({
  placeholder,
  disabled,
  error,
  icon,
  className,
  size = "sm",
  prefix,
  children,
  ...props
}: {
  placeholder?: string;
  disabled?: boolean;
  error?: boolean;
  icon?: React.ReactNode;
  className?: string;
  size?: "sm" | "default";
  prefix?: string;
  children?: React.ReactNode;
} & React.ButtonHTMLAttributes<HTMLButtonElement>) => {
  const context = React.useContext(SelectContext);
  if (!context) throw new Error("SelectTrigger must be used within Select");

  const selectedValue = context.value;
  const options = context.getOptions?.() || [];
  const selectedLabel = selectedValue && options.find((opt) => opt.value === selectedValue)?.label;

  const handleKeyDown = (event: React.KeyboardEvent) => {
    if (disabled) return;

    const { key } = event;
    const { isOpen, focusedIndex, setFocusedIndex, onOpenChange, onChange, handleTypeahead } = context;
    const options = context.getOptions?.() || [];

    if (!options || options.length === 0) return;

    switch (key) {
      case "ArrowDown":
        event.preventDefault();
        if (!isOpen) {
          onOpenChange?.(true);
        } else {
          const currentIndex = focusedIndex ?? -1;
          const nextIndex = currentIndex < options.length - 1 ? currentIndex + 1 : 0;
          setFocusedIndex?.(nextIndex);
        }
        break;

      case "ArrowUp":
        event.preventDefault();
        if (!isOpen) {
          onOpenChange?.(true);
        } else {
          const currentIndex = focusedIndex ?? -1;
          const prevIndex = currentIndex > 0 ? currentIndex - 1 : options.length - 1;
          setFocusedIndex?.(prevIndex);
        }
        break;

      case "Enter":
      case " ":
        event.preventDefault();
        if (!isOpen) {
          onOpenChange?.(true);
        } else if (focusedIndex !== undefined && focusedIndex >= 0 && focusedIndex < options.length) {
          onChange?.(options[focusedIndex].value);
        }
        break;

      case "Escape":
        event.preventDefault();
        onOpenChange?.(false);
        break;

      case "Tab":
        if (isOpen) {
          onOpenChange?.(false);
        }
        break;

      default:
        if (key.length === 1 && !event.ctrlKey && !event.altKey && !event.metaKey) {
          event.preventDefault();
          handleTypeahead?.(key);
        }
        break;
    }
  };

  return (
    <PopoverTrigger asChild>
      <Button
        variant={error ? "destructive" : "outline"}
        disabled={disabled}
        onClick={() => context.onOpenChange?.(!context.isOpen)}
        onKeyDown={handleKeyDown}
        data-slot="select-trigger"
        data-size={size}
        className={cn(
          "uci-border-[#383838] uci-text-[#FBFBFB] hover:uci-border-border/50 focus-within:uci-outline-primary uci-flex uci-w-full uci-px-3 uci-ring-4 uci-ring-transparent uci-outline-4 uci-border-solid disabled:uci-cursor-not-allowed uci-mb-0 uci-justify-between",
          context.isOpen && "focus-within:uci-outline-primary",
          disabled ? "uci-justify-start !uci-bg-[#242424] uci-border-border" : "uci-justify-between !uci-bg-[#111111]",
          className
        )}
        id={context.id}
        {...props}
      >
        {icon && <div className="uci-text-primary uci-absolute uci-top-1/2 uci-left-3 uci--translate-y-1/2">{icon}</div>}
        <span className="uci-flex-1 uci-min-w-0 uci-flex uci-items-center uci-overflow-hidden">
          {prefix && <span className="uci-text-[#ABABAB] uci-mr-2 uci-flex-shrink-0">{prefix}:</span>}
          {children ||
          <span className={cn("uci-text-[#FBFBFB] uci-truncate uci-whitespace-nowrap uci-overflow-hidden")}>
            {selectedLabel || placeholder}
          </span>}
        </span>
        {!disabled &&
          <ChevronDown
            className="uci-text-white uci-size-4 uci-flex-shrink-0 uci-transition-transform uci-duration-200"
            style={{
              transform: context.isOpen ? 'rotate(180deg)' : 'rotate(0deg)'
            }}
          />
        }
      </Button>
    </PopoverTrigger>
  );
};

const SelectContent = ({
  className,
  children,
  ...props
}: {
  className?: string;
  children: React.ReactNode;
} & React.HTMLAttributes<HTMLDivElement>) => {
  const context = React.useContext(SelectContext);
  if (!context) throw new Error("SelectContent must be used within Select");

  const contentRef = React.useRef<HTMLDivElement>(null);

  React.useEffect(() => {
    if (context.isOpen && contentRef.current) {
      contentRef.current.focus();
      if (context.suppressInitialScroll) {
        // Ensure we start at top so search input visible.
        contentRef.current.scrollTop = 0;
        // Focus search input if present.
        const searchInput = contentRef.current.querySelector<HTMLInputElement>("input[data-slot='select-search']");
        if (searchInput) searchInput.focus();
      }
    }
  }, [context.isOpen, context.suppressInitialScroll]);

  const handleKeyDown = (event: React.KeyboardEvent) => {
    const { key } = event;
    const { focusedIndex, setFocusedIndex, onChange, onOpenChange, handleTypeahead, getOptions } = context;
    const options = getOptions?.() || [];

    if (!options || options.length === 0) return;

    switch (key) {
      case "ArrowDown": {
        event.preventDefault();
        const currentIndex = focusedIndex ?? -1;
        const nextIndex = currentIndex < options.length - 1 ? currentIndex + 1 : 0;
        setFocusedIndex?.(nextIndex);
        break;
      }
      case "ArrowUp": {
        event.preventDefault();
        const prevCurrentIndex = focusedIndex ?? -1;
        const prevIndex = prevCurrentIndex > 0 ? prevCurrentIndex - 1 : options.length - 1;
        setFocusedIndex?.(prevIndex);
        break;
      }
      case "Enter": {
        event.preventDefault();
        if (focusedIndex !== undefined && focusedIndex >= 0 && focusedIndex < options.length) {
          onChange?.(options[focusedIndex].value);
        }
        break;
      }
      case "Escape": {
        event.preventDefault();
        onOpenChange?.(false);
        break;
      }
      default: {
        if (key.length === 1 && !event.ctrlKey && !event.altKey && !event.metaKey) {
          event.preventDefault();
          handleTypeahead?.(key);
        }
        break;
      }
    }
  };

  return (
    <PopoverContent 
      side="bottom" 
      align="start" 
      sideOffset={2}
      className={cn("uci-w-[var(--trigger-width)] uci-p-1 uci-outline-none !uci-overflow-visible", className)}
    >
      <div
        ref={contentRef}
        data-slot="select-content"
        tabIndex={0}
        role="listbox"
        onKeyDown={handleKeyDown}
        className="uci-outline-none uci-max-h-[calc(100vh-var(--trigger-top)-var(--trigger-height)-2rem)] uci-overflow-y-auto"
        {...props}
      >
        {children}
      </div>
    </PopoverContent>
  );
};

const SelectLabel = ({ className, ...props }: React.HTMLAttributes<HTMLDivElement>) => {
  return (
    <div data-slot="select-label" className={cn("uci-text-muted-foreground uci-px-2 uci-py-1.5 uci-text-xs", className)} {...props} />
  );
};

const SelectItem = ({
  value,
  children,
  className,
  ...props
}: {
  value: string;
  children: React.ReactNode;
  className?: string;
} & React.ButtonHTMLAttributes<HTMLButtonElement>) => {
  const context = React.useContext(SelectContext);
  if (!context) throw new Error("SelectItem must be used within Select");

  const itemRef = React.useRef<HTMLButtonElement>(null);

  React.useEffect(() => {
    const label = typeof children === "string" ? children : value;
    context.registerOption?.(value, label);

    return () => {
      context.unregisterOption?.(value);
    };
  }, [value, children, context.registerOption, context.unregisterOption]);

  const isSelected = value === context.value;
  const options = context.getOptions?.() || [];
  const itemIndex = options.findIndex((opt) => opt.value === value);
  const isFocused = itemIndex === context.focusedIndex;

  // Scroll focused item into view
  React.useEffect(() => {
    if (isFocused && itemRef.current) {
      if (context.suppressInitialScroll && context.focusedIndex === -1) return; // skip scroll for initial open when suppressed
      itemRef.current.scrollIntoView({ block: "nearest", behavior: "smooth" });
    }
  }, [isFocused]);

  const handleKeyDown = (event: React.KeyboardEvent) => {
    if (event.key === "Enter") {
      event.preventDefault();
      context.onChange?.(value);
    }
  };

  return (
    <button
      ref={itemRef}
      type="button"
      onClick={() => context.onChange?.(value)}
      onKeyDown={handleKeyDown}
      onMouseEnter={() => {
        if (itemIndex >= 0) {
          context.setFocusedIndex?.(itemIndex);
        }
      }}
      data-slot="select-item"
      className={cn(
        "uci-bg-[#171717] uci-relative uci-flex uci-w-full uci-items-center uci-justify-between uci-rounded uci-px-2 uci-py-1.5 uci-text-sm uci-outline-hidden uci-select-none uci-text-white",
        isSelected && "uci-text-[#99A7F1]",
        isFocused && "!uci-bg-[#111111]",
        className
      )}
      {...props}
    >
      <span>{children}</span>
      {isSelected && <Check className="uci-text-primary uci-size-4" />}
    </button>
  );
};

const SelectSeparator = ({ className, ...props }: React.HTMLAttributes<HTMLDivElement>) => {
  return (
    <div
      data-slot="select-separator"
      className={cn("uci-bg-border uci-pointer-events-none uci--mx-1 uci-my-1 uci-h-px", className)}
      {...props}
    />
  );
};

const SelectScrollUpButton = ({ className, ...props }: React.ButtonHTMLAttributes<HTMLButtonElement>) => {
  return (
    <button
      data-slot="select-scroll-up-button"
      className={cn("uci-flex uci-cursor-default uci-items-center uci-justify-center uci-py-1", className)}
      {...props}
    >
      <ChevronUp className="uci-size-4" />
    </button>
  );
};

const SelectScrollDownButton = ({ className, ...props }: React.ButtonHTMLAttributes<HTMLButtonElement>) => {
  return (
    <button
      data-slot="select-scroll-down-button"
      className={cn("uci-flex uci-cursor-default uci-items-center uci-justify-center uci-py-1", className)}
      {...props}
    >
      <ChevronDown className="uci-size-4" />
    </button>
  );
};

export {
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectLabel,
  SelectScrollDownButton,
  SelectScrollUpButton,
  SelectSeparator,
  SelectTrigger,
  SelectValue,
};
